ACTIVE_SESSIONS = {}

@app.get("/session")
def create_session(authorization: str = Header(None)):
    if authorization != f"Bearer {TOKEN}":
        raise HTTPException(status_code=403, detail="Unauthorized")
    session_id = str(uuid.uuid4())
    real_key = os.urandom(32)
    salt = os.urandom(32)
    key = PBKDF2(real_key, salt, dkLen=32, count=100000, hmac_hash_module=SHA512)
    ACTIVE_SESSIONS[session_id] = {'key': key, 'expires': time.time() + 300}
    return {'session_id': session_id, 'key': real_key.hex(), 'salt': salt.hex()}

@app.get("/payload/{session_id}")
def get_payload(session_id: str, authorization: str = Header(None)):
    if authorization != f"Bearer {TOKEN}":
        raise HTTPException(status_code=403, detail="Unauthorized")
    session = ACTIVE_SESSIONS.get(session_id)
    if not session or time.time() > session['expires']:
        raise HTTPException(status_code=410, detail="Session expired")
    nonce = os.urandom(12)
    cipher = AES.new(session['key'], AES.MODE_GCM, nonce=nonce)
    ct, tag = cipher.encrypt_and_digest(PAYLOAD)
    payload_enc = base64.b64encode(nonce + ct + tag).decode()
    return {'payload': payload_enc, 'perm': PERM}

